def matrix_multiply(A, B):
    rows_A = len(A)
    cols_A = len(A[0])
    rows_B = len(B)
    cols_B = len(B[0])

    if cols_A != rows_B:
        raise ValueError("Matris boyutları çarpma işlemi için uyumlu değil.")

    C = [[0 for _ in range(cols_B)] for _ in range(rows_A)]

    for i in range(rows_A):
        for j in range(cols_B):
            for k in range(cols_A):
                C[i][j] += A[i][k] * B[k][j]
    return C

def identity_matrix(size):
    return [[1 if i == j else 0 for j in range(size)] for i in range(size)]

def matrix_power(A, n):
    rows = len(A)
    cols = len(A[0])
    if rows != cols:
        raise ValueError("Matris kare olmalıdır.")

    L = rows

    if n < 0:
        raise ValueError("Üs negatif olamaz.")

    result = identity_matrix(L)

    current_power_of_A = A

    temp_n = n
    while temp_n > 0:
        if temp_n % 2 == 1:
            result = matrix_multiply(result, current_power_of_A)
        current_power_of_A = matrix_multiply(current_power_of_A, current_power_of_A)
        temp_n //= 2
    return result
